    ) {
        self.bibcode = bibcode
        self.title = title
        self.authors = authors
        self.year = year
        self.publication = publication
        self.doi = doi
        self.arxivId = arxivId
        self.abstractText = abstractText
        self.citationCount = citationCount
        self.pdfLinks = pdfLinks
        self.webUrl = webUrl
        self.isOpenAccess = isOpenAccess
        self.doctype = doctype
    }
}

// MARK: - ScixLibrary

/// ADS / SciX personal library metadata.
public struct ScixLibrary: Sendable {
    public var id: String
    public var name: String
    public var description: String
    public var numDocuments: Int32
    public var isPublic: Bool
    public var owner: String
    /// User's permission level: "owner" | "admin" | "write" | "read"
    public var permission: String

    public init(id: String, name: String, description: String, numDocuments: Int32, isPublic: Bool, owner: String, permission: String = "") {
        self.id = id
        self.name = name
        self.description = description
        self.numDocuments = numDocuments
        self.isPublic = isPublic
        self.owner = owner
        self.permission = permission
    }
}

// MARK: - ScixPermission

/// A collaborator permission entry for a SciX library.
public struct ScixPermission: Equatable, Sendable, Identifiable {
    public var email: String
    /// Permission level: "owner" | "admin" | "write" | "read"
    public var permission: String

    public var id: String { email }

    public init(email: String, permission: String) {
        self.email = email
        self.permission = permission
    }
}

// MARK: - ScixLibraryDetail

/// ADS / SciX personal library with its bibcodes.
public struct ScixLibraryDetail: Sendable {
    public var id: String
    public var name: String
    public var description: String
    public var numDocuments: Int32
    public var isPublic: Bool
    public var owner: String
    /// Bibcodes of all papers in this library
    public var bibcodes: [String]

    public init(id: String, name: String, description: String, numDocuments: Int32, isPublic: Bool, owner: String, bibcodes: [String]) {
        self.id = id
        self.name = name
        self.description = description
        self.numDocuments = numDocuments
        self.isPublic = isPublic
        self.owner = owner
        self.bibcodes = bibcodes
    }
}

// MARK: - ScixFfiError

/// Errors from the scix-client-ffi Rust layer.
public enum ScixFfiError: Error, Sendable {
    case apiError(message: String)
    case networkError(message: String)
    case unauthorized
    case rateLimited
    case notFound
    case `internal`(message: String)
}

extension ScixFfiError: LocalizedError {
    public var errorDescription: String? {
        switch self {
        case .apiError(let message): return "ADS API error: \(message)"
        case .networkError(let message): return "Network error: \(message)"
        case .unauthorized: return "ADS API key invalid or missing"
        case .rateLimited: return "ADS rate limit exceeded"
        case .notFound: return "Not found in ADS"
        case .`internal`(let message): return "Internal error: \(message)"
        }
    }
}

